func clipHookScore(text string) int {
	score := 55
	lower := strings.ToLower(text)
	for _, term := range []string{"why", "how", "mistake", "secret", "truth", "surprising", "stop", "start"} {
		if strings.Contains(lower, term) {
			score += 8
		}
	}
	if strings.Contains(text, "?") || strings.Contains(text, "!") {
		score += 10
	}
	if score > 100 {
		score = 100
	}
	return score
}

func clipValueScore(text string) int {
	score := 60
	lower := strings.ToLower(text)
	for _, term := range []string{"framework", "example", "practical", "step", "lesson", "because", "result", "focus"} {
		if strings.Contains(lower, term) {
			score += 7
		}
	}
	if score > 100 {
		score = 100
	}
	return score
}

func aspectSuffix(aspect string) string {
	return strings.ReplaceAll(strings.ReplaceAll(strings.TrimSpace(aspect), ":", "x"), "/", "x")
}
